GRANT ALL PRIVILEGES ON roomEase.* TO 'chhoungech'@'localhost'; FLUSH PRIVILEGES;
-- -----------------------------------------------------
-- 1. Table: USERS
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `USERS` (
  `uuid` VARCHAR(36) NOT NULL,
  `full_name` VARCHAR(255) NOT NULL,
  `email` VARCHAR(255) NOT NULL,
  `password_hash` VARCHAR(255) NOT NULL,
  `role` ENUM('RENTER', 'OWNER', 'ADMIN') NOT NULL,
  `avatar_url` VARCHAR(255) NULL,
  `phone_number` VARCHAR(50) NULL,
  `google_id` VARCHAR(255) NULL,
  `facebook_id` VARCHAR(255) NULL,
  `is_verified` BOOLEAN NOT NULL DEFAULT FALSE,
  `is_banned` BOOLEAN NOT NULL DEFAULT FALSE,
  `last_login_at` DATETIME NULL,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  UNIQUE INDEX `email_UNIQUE` (`email` ASC),
  UNIQUE INDEX `google_id_UNIQUE` (`google_id` ASC),
  UNIQUE INDEX `facebook_id_UNIQUE` (`facebook_id` ASC)
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 2. Table: ROOMS
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `ROOMS` (
  `uuid` VARCHAR(36) NOT NULL,
  `owner_id` VARCHAR(36) NOT NULL,
  `title` VARCHAR(255) NOT NULL,
  `description` TEXT NULL,
  `price_per_month` DECIMAL(10, 2) NOT NULL,
  `deposit` DECIMAL(10, 2) NOT NULL DEFAULT 0.00,
  `address` VARCHAR(255) NOT NULL,
  `district` VARCHAR(100) NOT NULL,
  `city` VARCHAR(100) NOT NULL,
  `location` POINT NOT NULL,
  `room_type` ENUM('STUDIO', '1BR', '2BR', 'SHARED') NOT NULL,
  `status` ENUM('AVAILABLE', 'RENTED') NOT NULL DEFAULT 'AVAILABLE',
  `approval_status` ENUM('PENDING', 'APPROVED', 'REJECTED') NOT NULL DEFAULT 'PENDING',
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  SPATIAL INDEX `location_SPATIAL` (`location`),
  CONSTRAINT `fk_rooms_owner`
    FOREIGN KEY (`owner_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 3. Table: AMENITIES
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `AMENITIES` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `name` VARCHAR(100) NOT NULL,
  `icon` VARCHAR(100) NULL,
  PRIMARY KEY (`id`),
  UNIQUE INDEX `name_UNIQUE` (`name` ASC)
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 4. Table: ROOM_AMENITIES (Many-to-Many Bridge)
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `ROOM_AMENITIES` (
  `room_id` VARCHAR(36) NOT NULL,
  `amenity_id` INT NOT NULL,
  PRIMARY KEY (`room_id`, `amenity_id`),
  CONSTRAINT `fk_room_amenities_room`
    FOREIGN KEY (`room_id`)
    REFERENCES `ROOMS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_room_amenities_amenity`
    FOREIGN KEY (`amenity_id`)
    REFERENCES `AMENITIES` (`id`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 5. Table: ROOM_IMAGES
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `ROOM_IMAGES` (
  `uuid` VARCHAR(36) NOT NULL,
  `room_id` VARCHAR(36) NOT NULL,
  `image_url` VARCHAR(255) NOT NULL,
  `is_primary` BOOLEAN NOT NULL DEFAULT FALSE,
  `sort_order` INT NOT NULL DEFAULT 0,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  CONSTRAINT `fk_room_images_room`
    FOREIGN KEY (`room_id`)
    REFERENCES `ROOMS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 6. Table: SAVED_ROOMS
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `SAVED_ROOMS` (
  `uuid` VARCHAR(36) NOT NULL,
  `user_id` VARCHAR(36) NOT NULL,
  `room_id` VARCHAR(36) NOT NULL,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  UNIQUE INDEX `user_room_UNIQUE` (`user_id` ASC, `room_id` ASC),
  CONSTRAINT `fk_saved_rooms_user`
    FOREIGN KEY (`user_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_saved_rooms_room`
    FOREIGN KEY (`room_id`)
    REFERENCES `ROOMS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 7. Table: VIEWING_REQUESTS
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `VIEWING_REQUESTS` (
  `uuid` VARCHAR(36) NOT NULL,
  `room_id` VARCHAR(36) NOT NULL,
  `renter_id` VARCHAR(36) NOT NULL,
  `owner_id` VARCHAR(36) NOT NULL,
  `requested_date` DATE NOT NULL,
  `requested_time` TIME NOT NULL,
  `status` ENUM('PENDING', 'APPROVED', 'REJECTED', 'SUGGESTED') NOT NULL DEFAULT 'PENDING',
  `suggested_date` DATE NULL,
  `suggested_time` TIME NULL,
  `notes` TEXT NULL,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  CONSTRAINT `fk_viewing_room`
    FOREIGN KEY (`room_id`)
    REFERENCES `ROOMS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_viewing_renter`
    FOREIGN KEY (`renter_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_viewing_owner`
    FOREIGN KEY (`owner_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 8. Table: CONVERSATIONS
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `CONVERSATIONS` (
  `uuid` VARCHAR(36) NOT NULL,
  `room_id` VARCHAR(36) NOT NULL,
  `renter_id` VARCHAR(36) NOT NULL,
  `owner_id` VARCHAR(36) NOT NULL,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  CONSTRAINT `fk_conversation_room`
    FOREIGN KEY (`room_id`)
    REFERENCES `ROOMS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_conversation_renter`
    FOREIGN KEY (`renter_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_conversation_owner`
    FOREIGN KEY (`owner_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 9. Table: MESSAGES
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `MESSAGES` (
  `uuid` VARCHAR(36) NOT NULL,
  `conversation_id` VARCHAR(36) NOT NULL,
  `sender_id` VARCHAR(36) NOT NULL,
  `content` TEXT NOT NULL,
  `is_read` BOOLEAN NOT NULL DEFAULT FALSE,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  CONSTRAINT `fk_messages_conversation`
    FOREIGN KEY (`conversation_id`)
    REFERENCES `CONVERSATIONS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_messages_sender`
    FOREIGN KEY (`sender_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 10. Table: REVIEWS
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `REVIEWS` (
  `uuid` VARCHAR(36) NOT NULL,
  `room_id` VARCHAR(36) NOT NULL,
  `user_id` VARCHAR(36) NOT NULL,
  `rating` INT NOT NULL,
  `comment` TEXT NULL,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  CONSTRAINT `chk_review_rating` CHECK (`rating` BETWEEN 1 AND 5),
  CONSTRAINT `fk_reviews_room`
    FOREIGN KEY (`room_id`)
    REFERENCES `ROOMS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_reviews_user`
    FOREIGN KEY (`user_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 11. Table: UNIVERSITIES
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `UNIVERSITIES` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `name` VARCHAR(255) NOT NULL,
  `location` POINT NOT NULL,
  `address` VARCHAR(255) NULL,
  PRIMARY KEY (`id`),
  UNIQUE INDEX `name_UNIQUE` (`name` ASC),
  SPATIAL INDEX `location_SPATIAL` (`location`)
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 12. Table: NEARBY_UNIVERSITIES
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `NEARBY_UNIVERSITIES` (
  `room_id` VARCHAR(36) NOT NULL,
  `university_id` INT NOT NULL,
  `distance_km` DECIMAL(5, 2) NOT NULL,
  `walk_minutes` INT NULL,
  PRIMARY KEY (`room_id`, `university_id`),
  CONSTRAINT `fk_nearby_uni_room`
    FOREIGN KEY (`room_id`)
    REFERENCES `ROOMS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE,
  CONSTRAINT `fk_nearby_uni_university`
    FOREIGN KEY (`university_id`)
    REFERENCES `UNIVERSITIES` (`id`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 13. Table: NOTIFICATIONS
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `NOTIFICATIONS` (
  `uuid` VARCHAR(36) NOT NULL,
  `user_id` VARCHAR(36) NOT NULL,
  `type` VARCHAR(50) NOT NULL,
  `reference_id` VARCHAR(36) NULL,
  `message` TEXT NOT NULL,
  `is_read` BOOLEAN NOT NULL DEFAULT FALSE,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  CONSTRAINT `fk_notifications_user`
    FOREIGN KEY (`user_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;

-- -----------------------------------------------------
-- 14. Table: SEARCH_HISTORY
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `SEARCH_HISTORY` (
  `uuid` VARCHAR(36) NOT NULL,
  `user_id` VARCHAR(36) NOT NULL,
  `keyword` VARCHAR(255) NULL,
  `city` VARCHAR(100) NULL,
  `district` VARCHAR(100) NULL,
  `min_price` DECIMAL(10, 2) NULL,
  `max_price` DECIMAL(10, 2) NULL,
  `room_type` ENUM('STUDIO', '1BR', '2BR', 'SHARED') NULL,
  `searched_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`uuid`),
  CONSTRAINT `fk_search_history_user`
    FOREIGN KEY (`user_id`)
    REFERENCES `USERS` (`uuid`)
    ON DELETE CASCADE
    ON UPDATE CASCADE
) ENGINE = InnoDB;


-- These 6 indexes cover ~80% of your performance risk
CREATE INDEX idx_rooms_owner    ON ROOMS(owner_id);
CREATE INDEX idx_rooms_search   ON ROOMS(approval_status, status, district, price_per_month);
CREATE INDEX idx_messages_conv  ON MESSAGES(conversation_id, created_at);
CREATE INDEX idx_notif_user     ON NOTIFICATIONS(user_id, is_read, created_at DESC);
CREATE INDEX idx_conv_renter    ON CONVERSATIONS(renter_id, updated_at DESC);
CREATE INDEX idx_conv_owner     ON CONVERSATIONS(owner_id, updated_at DESC);



